module div_8bit(
    input [7:0] dividend,
    input [7:0] divisor,
    input is_signed,
    output [15:0] result
);

    // Determine the sign of the result
    wire result_sign = is_signed && ((dividend[7] ^ divisor[7]) && (divisor[7] || dividend[7]));

    // Convert inputs to positive
    wire [7:0] abs_dividend = is_signed ? (dividend[7] ? -dividend : dividend) : dividend;
    wire [7:0] abs_divisor = is_signed ? (divisor[7] ? -divisor : divisor) : divisor;

    // Division algorithm
    reg [15:0] dividend_copy;
    reg [7:0] divisor_copy;
    reg [15:0] quotient;
    integer i;

    always @(*) begin
        dividend_copy = {8'b0, abs_dividend};
        divisor_copy = abs_divisor;
        quotient = 0;

        for (i = 0; i < 8; i = i + 1) begin
            dividend_copy = {dividend_copy[14:0], 1'b0};
            if (dividend_copy[15:8] >= divisor_copy) begin
                dividend_copy[15:8] = dividend_copy[15:8] - divisor_copy;
                quotient = {quotient[6:0], 1'b1};
            end else begin
                quotient = {quotient[6:0], 1'b0};
            end
        end
    end

    // Apply the sign to the result
    assign result = result_sign ? -{quotient, dividend_copy[7:0]} : {quotient, dividend_copy[7:0]};

endmodule
